window.bookSummaryJSON = "<p>This is an omnibus edition that contains books four to six of the Corps Justice Series: <i>Presidential Shift</i>, <i>National Burden</i>, and <i>Lethal Misconduct</i>.</p> <p>These are three action thriller books that are sure to keep you listening on.</p> <p><i>Presidential Shift</i>:</p> <p>The vice president killed. The first lady attacked. A president on the edge.</p> <p><i>National Burden</i>:</p> <p>A new president under pressure. Threats coming from every angle. The SSI team caught in the middle.</p> <p><i>Lethal Misconduct</i>:</p> <p>A ray of hope for millions. Powerful forces move to stop it. A marine and his team play for keeps.</p>"; 
